/**
 * VYRA Theme Catalog Module
 * ==========================
 * Sistem Parametreleri > Tasarım sekmesinde
 * hazır + özel SaaS temalarını firma bazlı kart grid görünümünde listeler.
 * v3.2.0 — Firma filtresi, önizleme butonu, özel tema badge, aktif işareti, uygula butonu
 */
window.ThemeCatalogModule = (function () {
    'use strict';

    const API_BASE = window.API_BASE_URL || '';
    let themes = [];
    let companies = [];
    let selectedCompanyId = null;
    let companyAssignments = []; // firmaya atanmış temalar
    let defaultThemeId = null;   // firmanın aktif (varsayılan) tema ID'si

    function getToken() {
        return localStorage.getItem('access_token') || '';
    }

    /* --- Companies yükle --- */
    async function loadCompanies() {
        try {
            // v3.34.0: vyraFetch — Auth + JSON + friendly error helper'da.
            companies = await window.vyraFetch('/companies/');
            // İlk firmayı otomatik seç
            if (companies.length > 0 && !selectedCompanyId) {
                selectedCompanyId = companies[0].id;
            }
        } catch (err) {
            console.warn('[ThemeCatalog] Firma listesi alınamadı');
        }
    }

    /* --- Firmaya atanmış temaları yükle --- */
    async function loadCompanyAssignments() {
        if (!selectedCompanyId) {
            companyAssignments = [];
            defaultThemeId = null;
            return;
        }
        try {
            // v3.34.0: vyraFetch — Auth + JSON + friendly error helper'da.
            companyAssignments = await window.vyraFetch('/themes/company/' + selectedCompanyId);
            var def = companyAssignments.find(function (a) { return a.is_default; });
            defaultThemeId = def ? def.id : null;
        } catch (err) {
            console.warn('[ThemeCatalog] Firma tema atamaları alınamadı');
            companyAssignments = [];
            defaultThemeId = null;
        }
    }

    /* --- Firma dropdown render --- */
    function renderCompanyFilter() {
        var wrap = document.getElementById('themeCatalogFilterWrap');
        if (!wrap || companies.length === 0) return;

        var opts = companies.map(function (c) {
            return '<option value="' + c.id + '"' + (c.id === selectedCompanyId ? ' selected' : '') + '>' + escapeHtml(c.name) + '</option>';
        }).join('');

        wrap.innerHTML =
            '<div class="tc-filter-bar">' +
                '<i class="fa-solid fa-building"></i>' +
                '<label class="tc-filter-label">Firma:</label>' +
                '<select id="themeCatalogCompanySelect" class="tc-filter-select">' +
                    opts +
                '</select>' +
            '</div>';

        var sel = document.getElementById('themeCatalogCompanySelect');
        if (sel) {
            sel.addEventListener('change', function () {
                selectedCompanyId = this.value ? parseInt(this.value) : null;
                loadThemes();
            });
        }
    }

    /* --- Tema yükle --- */
    async function loadThemes() {
        var grid = document.getElementById('themeCatalogGrid');
        if (!grid) return;

        grid.innerHTML = '<div class="tc-loading"><i class="fa-solid fa-spinner fa-spin"></i> Temalar yükleniyor...</div>';

        try {
            var path = '/themes/';
            if (selectedCompanyId) {
                path += '?company_id=' + selectedCompanyId;
            } else {
                path += '?include_custom=true';
            }

            // v3.34.0: vyraFetch — Auth + JSON + friendly error helper'da.
            themes = await window.vyraFetch(path);

            themes = themes.map(function (t) {
                if (typeof t.preview_colors === 'string') {
                    try { t.preview_colors = JSON.parse(t.preview_colors); } catch (e) { /* ignore */ }
                }
                return t;
            });

            // Firma atamalarını yükle
            await loadCompanyAssignments();

            renderGrid(grid);
        } catch (err) {
            console.error('[ThemeCatalog] Yükleme hatası:', err);
            grid.innerHTML = '<p class="tc-error">Tema listesi yüklenemedi.</p>';
        }
    }

    /* --- Kart grid render --- */
    function renderGrid(grid) {
        if (!themes.length) {
            grid.innerHTML = '<div class="tc-empty"><i class="fa-solid fa-palette"></i><p>Henüz tanımlı tema yok.</p></div>';
            return;
        }

        var hazir = themes.filter(function (t) { return !t.is_custom; });
        var ozel = themes.filter(function (t) { return t.is_custom; });

        var html = '';

        // Özet banner
        html += '<div class="tc-stats-banner">';
        html += '<span class="tc-stat"><i class="fa-solid fa-palette"></i> ' + themes.length + ' Tema</span>';
        if (hazir.length > 0) html += '<span class="tc-stat tc-stat-system"><i class="fa-solid fa-cubes"></i> ' + hazir.length + ' Hazır</span>';
        if (ozel.length > 0) html += '<span class="tc-stat tc-stat-custom"><i class="fa-solid fa-wand-magic-sparkles"></i> ' + ozel.length + ' Özel</span>';
        if (defaultThemeId) {
            var activeTheme = themes.find(function (t) { return t.id === defaultThemeId; });
            if (activeTheme) {
                html += '<span class="tc-stat tc-stat-active"><i class="fa-solid fa-circle-check"></i> Aktif: ' + escapeHtml(activeTheme.name) + '</span>';
            }
        }
        html += '</div>';

        // Hazır temalar
        if (hazir.length > 0) {
            html += '<div class="tc-section-title"><i class="fa-solid fa-cubes"></i> Hazır Temalar</div>';
            html += '<div class="tc-grid">';
            html += hazir.map(renderCard).join('');
            html += '</div>';
        }

        // Özel temalar
        if (ozel.length > 0) {
            html += '<div class="tc-section-title tc-section-custom"><i class="fa-solid fa-wand-magic-sparkles"></i> Özel Temalar</div>';
            html += '<div class="tc-grid">';
            html += ozel.map(renderCard).join('');
            html += '</div>';
        }

        grid.innerHTML = html;

        // Event bindings
        grid.querySelectorAll('.tc-preview-btn').forEach(function (btn) {
            btn.addEventListener('click', function (e) {
                e.stopPropagation();
                var themeId = parseInt(this.dataset.themeId);
                var theme = themes.find(function (t) { return t.id === themeId; });
                if (theme && window.ThemePreviewModal) {
                    window.ThemePreviewModal.open(theme);
                }
            });
        });

        grid.querySelectorAll('.tc-apply-btn').forEach(function (btn) {
            btn.addEventListener('click', function (e) {
                e.stopPropagation();
                var themeId = parseInt(this.dataset.themeId);
                applyTheme(themeId);
            });
        });
    }

    /* --- Tema uygula --- */
    function applyTheme(themeId) {
        if (!selectedCompanyId) {
            if (window.showToast) window.showToast('Lütfen önce bir firma seçin.', 'warning');
            return;
        }

        var theme = themes.find(function (t) { return t.id === themeId; });
        var themeName = theme ? theme.name : 'Tema #' + themeId;

        // Firma adını bul
        var companyName = '';
        var comp = companies.find(function (c) { return c.id === selectedCompanyId; });
        if (comp) companyName = comp.name;

        // VyraModal ile modern onay
        if (!window.VyraModal) {
            // Fallback: VyraModal yoksa eski confirm
            if (!confirm('"' + themeName + '" teması uygulanacak. Emin misiniz?')) return;
            executeApply(themeId, themeName, companyName);
            return;
        }

        VyraModal.confirm({
            title: 'Tema Uygula',
            message: '<strong>"' + escapeHtml(themeName) + '"</strong> teması <strong>' + escapeHtml(companyName) + '</strong> firmasına atanacak.<br><br>Tema renkleri anında uygulanacaktır.',
            confirmText: 'Uygula',
            cancelText: 'Vazgeç',
            onConfirm: function () {
                executeApply(themeId, themeName, companyName);
            }
        });
    }

    /* --- Tema atama API çağrısı ve branding güncelleme --- */
    async function executeApply(themeId, themeName, companyName) {
        try {
            // Mevcut atamaları al, yeni temayı default olarak ekle
            var assignedIds = companyAssignments.map(function (a) { return a.id; });
            if (assignedIds.indexOf(themeId) === -1) {
                assignedIds.push(themeId);
            }

            // v3.34.0: vyraFetch — Auth + JSON + friendly error helper'da.
            await window.vyraFetch('/themes/assign', {
                method: 'POST',
                body: {
                    company_id: selectedCompanyId,
                    theme_ids: assignedIds,
                    default_theme_id: themeId
                }
            });

            // Tema detayını (CSS variables dahil) API'den al
            var themeData = null;
            try {
                themeData = await window.vyraFetch('/themes/' + themeId);
            } catch (_) { /* detail eksik kalabilir — branding fallback'i devreye girer */ }

            // BrandingEngine cache güncelle — tema anında uygulanır
            if (window.BrandingEngine && themeData) {
                var brandData = BrandingEngine.loadBranding() || {};
                brandData.theme = themeData;
                BrandingEngine.saveBranding(brandData);

                // Sadece CSS temayı uygula (login içeriklerini dokunma — layout bozar)
                if (themeData.css_variables) {
                    var cssVars = themeData.css_variables;
                    if (typeof cssVars === 'string') {
                        try { cssVars = JSON.parse(cssVars); } catch(e) { cssVars = null; }
                    }
                    if (cssVars) {
                        BrandingEngine.applyThemeForCurrentMode(cssVars);
                    }
                }
            }

            if (window.showToast) window.showToast('"' + themeName + '" teması başarıyla uygulandı!', 'success');

            // Tema kataloğunu yeniden render et (aktif tema işaretini güncelle)
            await loadCompanyAssignments();
            var grid = document.getElementById('themeCatalogGrid');
            if (grid) renderGrid(grid);

        } catch (err) {
            console.error('[ThemeCatalog] Tema uygulama hatası:', err);
            if (window.showToast) window.showToast('Tema uygulanamadı: ' + err.message, 'error');
        }
    }

    /* --- Tek kart HTML --- */
    function renderCard(t) {
        var colors = (t.preview_colors || []).map(sanitizeColor);
        var gradientBar = colors.length >= 2
            ? 'background: linear-gradient(135deg, ' + colors[0] + ' 0%, ' + colors[1] + ' 100%);'
            : 'background: ' + (colors[0] || '#666') + ';';

        var isActive = (t.id === defaultThemeId);
        var isAssigned = companyAssignments.some(function (a) { return a.id === t.id; });

        var customBadge = t.is_custom
            ? '<span class="tc-badge-custom"><i class="fa-solid fa-star"></i> Özel</span>'
            : '';

        var activeBadge = isActive
            ? '<span class="tc-badge-active"><i class="fa-solid fa-circle-check"></i> Aktif</span>'
            : '';

        var cardClass = 'tc-card';
        if (isActive) cardClass += ' tc-card-active';
        else if (isAssigned) cardClass += ' tc-card-assigned';

        var applyBtnClass = isActive ? 'tc-apply-btn tc-apply-active' : 'tc-apply-btn';
        var applyBtnText = isActive ? '<i class="fa-solid fa-check"></i> Uygulandı' : '<i class="fa-solid fa-check-circle"></i> Uygula';
        var applyDisabled = isActive ? ' disabled' : '';

        return '<div class="' + cardClass + '" data-theme-id="' + t.id + '">' +
            customBadge + activeBadge +
            '<div class="tc-card-gradient" style="' + gradientBar + '"></div>' +
            '<div class="tc-card-body">' +
                '<h4 class="tc-card-title">' + escapeHtml(t.name) + '</h4>' +
                '<p class="tc-card-desc">' + escapeHtml(t.description || '') + '</p>' +
                '<div class="tc-card-colors">' +
                    colors.map(function (c) {
                        return '<span class="tc-color-dot" style="background:' + c + ';" title="' + c + '"></span>';
                    }).join('') +
                '</div>' +
            '</div>' +
            '<div class="tc-card-footer">' +
                '<button class="tc-preview-btn" data-theme-id="' + t.id + '" title="Tema Önizleme">' +
                    '<i class="fa-solid fa-eye"></i> Önizle' +
                '</button>' +
                '<button class="' + applyBtnClass + '" data-theme-id="' + t.id + '"' + applyDisabled + '>' +
                    applyBtnText +
                '</button>' +
            '</div>' +
        '</div>';
    }

    function escapeHtml(text) {
        if (!text) return '';
        var div = document.createElement('div');
        div.textContent = text;
        return div.innerHTML;
    }

    /** CSS color sanitize — sadece güvenli formatlar kabul edilir */
    function sanitizeColor(c) {
        if (!c || typeof c !== 'string') return '#666';
        // Hex, rgb, rgba, hsl, hsla, named colors (harf/rakam/virgül/parantez/yüzde/boşluk/nokta)
        if (/^[#a-zA-Z0-9(),%.\s]+$/.test(c)) return c;
        return '#666';
    }

    /* --- Init --- */
    async function load() {
        await loadCompanies();
        renderCompanyFilter();
        await loadThemes();
    }

    return { load: load, reload: loadThemes };
})();


/* === assets/js/modules/theme_preview_modal.js === */
/**
 * VYRA Theme Preview Modal
 * ========================
 * Login ekranını tema renkleriyle önizleme modalı.
 * iframe içinde login.html yüklenir, CSS variables inject edilir.
 * v3.2.0
 */
window.ThemePreviewModal = (function () {
    'use strict';

    const API_BASE = window.API_BASE_URL || '';
    let currentTheme = null;
    let currentMode = 'dark';
    let modalEl = null;

    function getToken() {
        return localStorage.getItem('access_token') || '';
    }

    /* --- Modal HTML oluştur --- */
    function ensureModal() {
        if (modalEl) return;

        var div = document.createElement('div');
        div.id = 'themePreviewOverlay';
        div.className = 'tpm-overlay';
        div.innerHTML =
            '<div class="tpm-container">' +
                '<div class="tpm-header">' +
                    '<div class="tpm-header-left">' +
                        '<div class="tpm-icon"><i class="fa-solid fa-eye"></i></div>' +
                        '<div>' +
                            '<h3 class="tpm-title">Tema Önizleme</h3>' +
                            '<span class="tpm-subtitle" id="tpmThemeName"></span>' +
                        '</div>' +
                    '</div>' +
                    '<div class="tpm-header-actions">' +
                        '<div class="tpm-mode-toggle">' +
                            '<button class="tpm-mode-btn active" data-mode="dark">' +
                                '<i class="fa-solid fa-moon"></i> Dark' +
                            '</button>' +
                            '<button class="tpm-mode-btn" data-mode="light">' +
                                '<i class="fa-solid fa-sun"></i> Light' +
                            '</button>' +
                        '</div>' +
                        '<button class="tpm-close" id="tpmClose" title="Kapat">' +
                            '<i class="fa-solid fa-xmark"></i>' +
                        '</button>' +
                    '</div>' +
                '</div>' +
                '<div class="tpm-body">' +
                    '<div class="tpm-iframe-wrap">' +
                        '<iframe id="tpmIframe" src="about:blank" class="tpm-iframe"></iframe>' +
                    '</div>' +
                '</div>' +
                '<div class="tpm-footer">' +
                    '<div class="tpm-footer-info">' +
                        '<i class="fa-solid fa-circle-info"></i> ' +
                        'Bu önizleme yalnızca görsel değerlendirme amaçlıdır. Uygulamak için firmaya tema atayın.' +
                    '</div>' +
                    '<button class="tpm-close-btn" id="tpmCloseBtn">Kapat</button>' +
                '</div>' +
            '</div>';

        document.body.appendChild(div);
        modalEl = div;

        // Event bindings
        document.getElementById('tpmClose').addEventListener('click', close);
        document.getElementById('tpmCloseBtn').addEventListener('click', close);

        // Mode toggle
        div.querySelectorAll('.tpm-mode-btn').forEach(function (btn) {
            btn.addEventListener('click', function () {
                div.querySelectorAll('.tpm-mode-btn').forEach(function (b) { b.classList.remove('active'); });
                this.classList.add('active');
                currentMode = this.dataset.mode;
                applyThemeToIframe();
            });
        });

        // ESC desteği
        document.addEventListener('keydown', function (e) {
            if (e.key === 'Escape' && modalEl && !modalEl.classList.contains('hidden')) {
                close();
            }
        });
    }

    /* --- Tema CSS variables'ı API'den al --- */
    async function fetchThemeFull(themeId) {
        try {
            // v3.34.0: vyraFetch — Auth + JSON + friendly error helper'da.
            return await window.vyraFetch('/themes/' + themeId);
        } catch (err) {
            console.error('[ThemePreview] Tema detayı alınamadı:', err);
            return null;
        }
    }

    /* --- Modal aç --- */
    async function open(theme) {
        ensureModal();

        document.getElementById('tpmThemeName').textContent = theme.name || '';

        // Tema detayını (CSS variables dahil) API'den al
        var fullTheme = await fetchThemeFull(theme.id);
        if (!fullTheme) {
            if (window.showToast) window.showToast('Tema detayı alınamadı', 'error');
            return;
        }

        currentTheme = fullTheme;

        // CSS variables parse
        if (typeof currentTheme.css_variables === 'string') {
            try { currentTheme.css_variables = JSON.parse(currentTheme.css_variables); } catch (e) { /* ignore */ }
        }

        currentMode = 'dark';
        modalEl.querySelectorAll('.tpm-mode-btn').forEach(function (b) {
            b.classList.toggle('active', b.dataset.mode === 'dark');
        });

        modalEl.classList.remove('hidden');
        modalEl.classList.add('visible');
        document.body.style.overflow = 'hidden';

        // iframe yükle
        loadIframe();
    }

    /* --- iframe login.html yükle --- */
    var originalBranding = null; // orijinal cache yedek
    var previewTimers = [];      // timer ID'leri — close'da temizlenir

    function clearPreviewTimers() {
        previewTimers.forEach(function(id) { clearTimeout(id); });
        previewTimers = [];
    }

    function loadIframe() {
        var iframe = document.getElementById('tpmIframe');
        if (!iframe) return;

        // Önceki timer'ları temizle
        clearPreviewTimers();

        // Orijinal branding cache'ini yedekle
        originalBranding = localStorage.getItem('vyra_company_branding');

        // Geçici olarak preview temasını localStorage'a yaz
        injectPreviewBranding();

        iframe.onload = function () {
            // Branding engine asenkron çalışıyor — birden fazla kez dene
            previewTimers.push(
                setTimeout(function () { forcePreviewTheme(); }, 600)
            );
            previewTimers.push(
                setTimeout(function () { forcePreviewTheme(); }, 1500)
            );
            previewTimers.push(
                setTimeout(function () {
                    forcePreviewTheme();
                    restoreOriginalBranding();
                }, 2500)
            );
        };

        // Login sayfasını yükle
        iframe.src = '/login.html?preview=1';
    }

    /* --- Preview temasını localStorage'a geçici yaz --- */
    function injectPreviewBranding() {
        if (!currentTheme) return;
        try {
            var brandData = originalBranding ? JSON.parse(originalBranding) : {};
            brandData.theme = currentTheme;
            localStorage.setItem('vyra_company_branding', JSON.stringify(brandData));
        } catch (e) {
            console.warn('[ThemePreview] branding cache yazma hatası:', e);
        }
    }

    /* --- Orijinal branding cache'ini geri yükle --- */
    function restoreOriginalBranding() {
        try {
            if (originalBranding) {
                localStorage.setItem('vyra_company_branding', originalBranding);
            } else {
                localStorage.removeItem('vyra_company_branding');
            }
        } catch (e) { /* ignore */ }
    }

    /* --- iframe'deki temayı zorla preview temasına çevir --- */
    function forcePreviewTheme() {
        var iframe = document.getElementById('tpmIframe');
        if (!iframe || !iframe.contentDocument || !currentTheme) return;

        try {
            var doc = iframe.contentDocument;
            var iframeWin = iframe.contentWindow;
            var root = doc.documentElement;

            root.setAttribute('data-theme', currentMode);

            var cssVars = currentTheme.css_variables;
            if (!cssVars) return;
            var modeVars = cssVars[currentMode] || cssVars.dark || {};

            // 1) Branding engine'in oluşturduğu accent override'ı KESİNLİKLE KALDIR
            var accentOverride = doc.getElementById('vyra-accent-override');
            if (accentOverride) accentOverride.remove();

            // 2) iframe BrandingEngine varsa preview temasıyla yeniden çağır
            if (iframeWin && iframeWin.BrandingEngine) {
                // Önce CSS kök değişkenleri uygula
                iframeWin.BrandingEngine.applyThemeCSS(modeVars);
                // Sonra accent override'ı DOĞRU renklerle oluştur
                iframeWin.BrandingEngine.applyThemeForCurrentMode(cssVars);
            }

            // 3) Kendi CSS değişkenlerimizi !important ile en sona ekle
            var existingStyle = doc.getElementById('theme-preview-inject');
            if (existingStyle) existingStyle.remove();

            var cssText = ':root, :root[data-theme="' + currentMode + '"] {\n';
            for (var key in modeVars) {
                if (modeVars.hasOwnProperty(key)) {
                    cssText += '  ' + key + ': ' + modeVars[key] + ' !important;\n';
                }
            }
            cssText += '}\n';

            var style = doc.createElement('style');
            style.id = 'theme-preview-inject';
            style.textContent = cssText;
            doc.head.appendChild(style);

            // 4) Önizleme badge
            if (!doc.getElementById('preview-badge')) {
                var badge = doc.createElement('div');
                badge.id = 'preview-badge';
                badge.style.cssText = 'position:fixed;top:12px;left:50%;transform:translateX(-50%);z-index:9999;' +
                    'background:rgba(0,0,0,0.7);backdrop-filter:blur(12px);color:#fff;padding:6px 16px;' +
                    'border-radius:20px;font-size:11px;font-weight:500;letter-spacing:0.5px;' +
                    'display:flex;align-items:center;gap:6px;pointer-events:none;';
                badge.innerHTML = '<span style="width:6px;height:6px;border-radius:50%;background:#22c55e;"></span> ÖNİZLEME MODU';
                doc.body.appendChild(badge);
            }
        } catch (err) {
            console.warn('[ThemePreview] forcePreviewTheme hatası:', err);
        }
    }

    /* --- Mod değişikliğinde tema yeniden uygula (dark/light toggle) --- */
    function applyThemeToIframe() {
        forcePreviewTheme();
    }

    /* --- Modal kapat --- */
    function close() {
        if (!modalEl) return;
        modalEl.classList.remove('visible');
        modalEl.classList.add('hidden');
        document.body.style.overflow = '';

        // Aktif timer'ları temizle (forcePreviewTheme artık çalışmasın)
        clearPreviewTimers();

        // Orijinal branding cache'ini geri yükle
        restoreOriginalBranding();

        // iframe temizle
        var iframe = document.getElementById('tpmIframe');
        if (iframe) iframe.src = 'about:blank';

        currentTheme = null;
    }

    return { open: open, close: close };
})();


