            if (!btn || !pane) return;
            const active = (n === name);
            btn.classList.toggle('ao-tab--active', active);
            btn.setAttribute('aria-selected', active ? 'true' : 'false');
            btn.tabIndex = active ? 0 : -1;
            pane.classList.toggle('ao-tab-pane--active', active);
            pane.hidden = !active;
